//With the Mayle--Rouse code
//This is for 20.36.1.a.1

SetSeed(508722640,0);
AttachSpec("TwistParametrized.spec");

N := 20;
gens := [[0, 1, 11, 7], [0, 1, 19, 1], [0, 3, 1, 0], [0, 3, 13, 1], [0, 11, 1, 17], [1, 7, 11, 16]];
ModEC := InitializeModEC(N,gens : precmult := 2, Verbose := true);
Iso, Mx := EllipticCurveQuoCandidates(ModEC);
pts := PointSearch(ModEC`XG,100);
assert #pts eq 2;
ModEC`BasePt := pts[1];
map1 := FindMapsToEC(ModEC, [[ 0, -1, 0, 4, -4 ]], [1]);  //f1: X -> E1
psi1 := map1[1];
map2 := FindMapsToEC(ModEC, [[ 0, 0, 0, 5, 10 ]], [1]);  //f2: X -> E2
psi2 := map2[1];
E1 := Codomain(psi1);
E2 := Codomain(psi2);
//check that the maps evaluate correctly
X := Domain(map1[1]);
pts := PointSearch(X, 100);
valpsi1pts1 := psi1(pts[1]); //long time to compute these
valpsi1pts2 := psi1(pts[2]); 
assert valpsi1pts1 eq valpsi1pts2;
assert valpsi1pts1 eq E1!0; 
assert psi2(pts[1]) ne psi2(pts[2]); //map to different points

// Compute fibers and check them
pre_im_psi2_x := (psi2(pts[1]))@@psi2;
pre_im_psi1_x:= (E1!0)@@psi1; //E1!0 is a replacement for psi1(pts[1])
assert Degree(pre_im_psi1_x meet pre_im_psi2_x) eq 1; //one point here
assert RationalPoints(pre_im_psi1_x meet pre_im_psi2_x)[1] eq pts[1]; //in fact its the point we are looking for


pre_im_psi1_xprime := (E1!0)@@psi1; //this is a replacement for psi1(pts[2])
pre_im_psi2_xprime := (psi2(pts[2]))@@psi2;
assert Degree(pre_im_psi1_xprime meet pre_im_psi2_xprime) eq 1; //one point here
assert RationalPoints(pre_im_psi1_xprime meet pre_im_psi2_xprime)[1] eq pts[2]; //also what we are looking for

//Now check that the non-special points are really the only ones in the fibers of the j-map
P5<x,y,z,w,t,u> := Ambient(Domain(map1[1]));
Xlmfdb := [x^2+x*y+x*z+z^2+w^2-x*u, y^2-y*z+2*x*t-z*t-w*t-t^2-t*u, y^2-z^2-x*t-y*t-z*t-2*w*t-y*u+z*u+t*u, x*y+x*z+3*y*z-z^2-y*w+x*t-z*t-x*u+2*y*u-z*u-t*u, x^2-2*x*y-x*z+z^2-y*w+z*w+w^2-x*t-2*w*t+x*u+y*u+z*u-w*u-u^2, x*y+y^2+y*z-z^2-2*y*w-z*w+2*x*t+3*z*t-2*w*t-t^2+y*u+w*u+t*u];
C := Curve(P5, Xlmfdb);
jmap := [3104917729547031250*x*w^12-66780307411742800000*x*w^11*u+594506561186574903125*x*w^10*u^2-271663450825329550000*x*w^9*u^3+878891038963604434375*x*w^8*u^4+5442021315901514717500*x*w^7*u^5+33936154682536692564375*x*w^6*u^6+217047617156872410743750*x*w^5*u^7+1342443443194825970102000*x*w^4*u^8+7955971063605849288914550*x*w^3*u^9+43785959194173612746221000*x*w^2*u^10+212146080692376341087150810*x*w*u^11-1659064550732119555917687351545*x*t^12-13291114891606211497725349848719*x*t^11*u-920413949901900658294955015339*x*t^10*u^2-48687782004083054858472677228218*x*t^9*u^3+144507735963512029529763032050439*x*t^8*u^4+96485898955302005973337490879843*x*t^7*u^5-115207526471355594882653359254323*x*t^6*u^6-53268275007368533759679295854842*x*t^5*u^7+20112857358644169303255898963746*x*t^4*u^8+7463129690784876272936108456432*x*t^3*u^9-900346444480784585753564492926*x*t^2*u^10-122945365024948758974804848833*x*t*u^11+776361971911232564663039905*x*u^12+4619604081344410127436102729270*y*w*t^11-1075269310776069156670992240316*y*w*t^10*u+11012480414656395893490008256405*y*w*t^9*u^2-21842724834478418506557400724710*y*w*t^8*u^3-103090443962482236668875236930000*y*w*t^7*u^4+64756285029029965206895394165125*y*w*t^6*u^5+55765603830523088106867570331024*y*w*t^5*u^6-14514568921111016444606039327445*y*w*t^4*u^7-9936580829393683885882058689130*y*w*t^3*u^8+1231254391739365613401386954645*y*w*t^2*u^9+209604187234061699989990267135*y*w*t*u^10-5786143501809575703641545154*y*w*u^11-1275041098930351504118855829115*y*t^12-4310947259055655218957768640144*y*t^11*u-7106675760127255843081541349668*y*t^10*u^2-11547267885338044510167135848340*y*t^9*u^3+39084617126234418694602625774252*y*t^8*u^4+73804368466892116894631390560518*y*t^7*u^5-27536387764429181725543377845257*y*t^6*u^6-45325108325989144408645646133776*y*t^5*u^7-619590695051105313156125559313*y*t^4*u^8+7232974910330787385795349346571*y*t^3*u^9+422849298902054999807794038781*y*t^2*u^10-186835268662426396138121228887*y*t*u^11-79406295944958845682